```typescript
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

async function aggregateData() {
  const data = await prisma.metric.aggregate({
    _sum: {
      click: true,
      spend: true,
      impressions: true,
    },
    _count: {
      campaignName: true,
    },
    include: {
      dimensions: true,
    },
  });

  return data;
}

async function queryData() {
  const data = await prisma.metric.findMany({
    include: {
      dimensions: true,
    },
  });

  return data;
}
```

