In Prisma, you can perform JOIN operations using the `include` directive with the `select` option in combination with the appropriate relationships defined in your Prisma schema.

Here's an example of how to query using JOIN in Prisma:

```typescript
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

async function queryData() {
  const data = await prisma.metric.findMany({
    select: {
      click: true,
      spend: true,
      impressions: true,
      dimensions: {
        select: {
          adId: true,
          statTimeDay: true,
          type: true,
        },
      },
    },
  });

  return data;
}

async function main() {
  const result = await queryData();
  console.log(result);
}

main()
  .catch((error) => {
    console.error(error);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
```

